#include <cstdlib>
#include <ctime>

using namespace std;

double calculateAverage(int *arr, int n) {
    double sum = 0;

    for (int i = 0; i < n; i++) {
        sum += arr[i];
    }

    return sum / n;
}

int countElementsLessThanAverage(int *arr, int n) {
    double average = calculateAverage(arr, n);
    int count = 0;

    for (int i = 0; i < n; i++) {
        if (arr[i] < average) {
            count++;
        }
    }

    return count;
}

int main() {
    int m, n;

    cout << "Введите размер M: ";
    cin >> m;

    cout << "Введите размер N: ";
    cin >> n;

    int a[m][n];

    srand(time(NULL)); // инициализация генератора случайных чисел

    cout << "Сгенерированная матрица:\n";
